641→      await fs.writeFile(targetPath, buffer);
642→      attachments.push({
643→        type: "image",
644→        path: targetPath,
645→        mime: imageMime,
646→        originalName: fileName,
647→      });
648→    }
649→
650→    if (normalizedMessage.documentMessage) {
651→      const buffer = await downloadMediaMessage(
652→        baileysMsg,
653→        "buffer",
654→        {},
655→        { logger: pino({ level: "silent" }) },
656→      );
657→      const docMime =
658→        normalizedMessage.documentMessage.mimetype ||
659→        "application/octet-stream";
660→      const originalName =
661→        normalizedMessage.documentMessage.fileName ||
662→        makeFileNameFromMime(baileysMsg.key.id || "document", "document", docMime);
663→      const safeName = originalName.replace(/[<>:"/\\|?*\u0000-\u001F]/g, "_");
664→      const targetPath = path.join(
665→        this.config.paths.inbox,
666→        `${compactTimestamp()}_${safeName}`,
667→      );
668→      await fs.writeFile(targetPath, buffer);
669→      attachments.push({
670→        type: "document",
671→        path: targetPath,
672→        mime: docMime,
673→        originalName: originalName,
674→      });
675→    }
676→
677→    return attachments;
678→  }
679→}
